-- ============================================
-- Legislacao full-site: jose-carlos-aleluia / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/74553
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = jose-carlos-aleluia-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 93
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=74553, tipo Deputado(a), ordemAssinatura=1.
-- 7 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'jose-carlos-aleluia';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'jose-carlos-aleluia: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao jose-carlos-aleluia: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2189605', '2189600', '2186218', '2181032', '2189604', '2189337', '2186217', '2181031', '2178242', '2178237', '2176656', '2189603', '2180423', '2178241', '2177215', '2173188', '2171022', '2189602', '2186220', '2182622', '2179407', '2178240', '2177214', '2174914', '2172651', '2169551', '2169546', '2163558', '2158425', '2158053', '2145682', '2145539', '2143265', '2189601', '2186219', '2179217', '2178239', '2177208', '2172151', '2169550', '2167570', '2163412', '2158164', '2156499', '2148878', '2145575', '2143739', '2143264', '2141458', '2176884', '2173855', '2172053', '2169549', '2166833', '2162625', '2158056', '2155975', '2148796', '2145542', '2143315', '2141768', '2138308', '2173757', '2169548', '2158055', '2152202', '2148795', '2145541', '2143267', '2141498', '2138307', '2169547', '2163979', '2159702', '2158054', '2150860', '2145683', '2145540', '2143266', '2141490', '2138306', '2141469', '2138305', '2138304', '2178924', '2178238', '2178726', '2174909', '2164596', '2172052', '2188760', '2178243', '2178724');
  IF target_present <> 93 THEN
    RAISE EXCEPTION 'Pre-condicao jose-carlos-aleluia: esperadas 93 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2189605', '2189600', '2186218', '2181032', '2189604', '2189337', '2186217', '2181031', '2178242', '2178237', '2176656', '2189603', '2180423', '2178241', '2177215', '2173188', '2171022', '2189602', '2186220', '2182622', '2179407', '2178240', '2177214', '2174914', '2172651', '2169551', '2169546', '2163558', '2158425', '2158053', '2145682', '2145539', '2143265', '2189601', '2186219', '2179217', '2178239', '2177208', '2172151', '2169550', '2167570', '2163412', '2158164', '2156499', '2148878', '2145575', '2143739', '2143264', '2141458', '2176884', '2173855', '2172053', '2169549', '2166833', '2162625', '2158056', '2155975', '2148796', '2145542', '2143315', '2141768', '2138308', '2173757', '2169548', '2158055', '2152202', '2148795', '2145541', '2143267', '2141498', '2138307', '2169547', '2163979', '2159702', '2158054', '2150860', '2145683', '2145540', '2143266', '2141490', '2138306', '2141469', '2138305', '2138304', '2178924', '2178238', '2178726', '2174909', '2164596', '2172052', '2188760', '2178243', '2178724')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'jose-carlos-aleluia-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao jose-carlos-aleluia: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao jose-carlos-aleluia: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

